SELECT COUNT(prediction_id) AS number_of_predictions
FROM predictions
WHERE model_id = 1;

SELECT prediction_id, model_id, date, correlation
FROM predictions
ORDER BY date DESC;

SELECT MAX(correlation) AS max_correlation
FROM predictions
WHERE model_id = 1;

SELECT correlation
FROM predictions
WHERE correlation > (SELECT AVG(correlation) FROM predictions);

SELECT prediction_id, model_id
FROM predictions
ORDER BY r_squared DESC;
